mapper.select:
select * from nx_customer_referral_reward_rule


        and community_id = #{communityId}


        and rule_code = #{ruleCode}


        and reward_target = #{rewardTarget}


        and enabled = #{enabled}


order by priority desc, nx_customer_referral_reward_rule_id desc

select count(*) from nx_customer_referral_reward_rule
where community_id = #{communityId}
  and rule_code = #{ruleCode}
  and reward_target = #{rewardTarget}
  and trigger_type = #{triggerType}
  and beneficiary_type = #{beneficiaryType}
  and enabled = 1
  and (rule_status is null or rule_status = 1)

      and nx_customer_referral_reward_rule_id != #{excludeRuleId}

  and (
    (effective_start_at is null and effective_end_at is null)
    or (#{effectiveStartAt} is null and #{effectiveEndAt} is null)
    or (
      (effective_start_at is null or effective_start_at <= IFNULL(#{effectiveEndAt}, '9999-12-31 23:59:59'))
      and (effective_end_at is null or effective_end_at >= IFNULL(#{effectiveStartAt}, '1970-01-01 00:00:00'))
    )
  )
